/* Generated by scripts/font-explore/generate-font-gallery.js — not hand-edited. */
function formatFontLabPasteCss(bodyFamily, headingFamily, options) {
  options = options || {};
  var headingScope = options.headingScope || 'all-headings';
  var monoStack =
    "ui-monospace, 'Cascadia Code', 'Source Code Pro', Menlo, Consolas, 'DejaVu Sans Mono', monospace";
  var webNote = options.webFont
    ? '/* Self-hosted WOFF2 required — see src/assets/css/font-lab-exploratory.css for @font-face. */'
    : '';

  if (headingScope === 'hgroup-only') {
    return [
      webNote,
      '/* Site title only on --font-family-display; article headings use body stack. */',
      '/* code/pre: UA styles use monospace; --font-family-mono sets it explicitly (not the body stack). */',
      '',
      ':root {',
      '  --font-family: ' + bodyFamily + ';',
      '  --font-family-display: ' + headingFamily + ';',
      '  --font-family-mono: ' + monoStack + ';',
      '}',
      '',
      'body {',
      '  font-family: var(--font-family);',
      '}',
      '',
      'hgroup h1 {',
      '  font-family: var(--font-family-display);',
      '}',
      '',
      'code, pre, kbd, samp {',
      '  font-family: var(--font-family-mono);',
      '}'
    ]
      .filter(function (line) {
        return line.length > 0;
      })
      .join('\n');
  }

  if (headingScope === 'h1-titles') {
    return [
      webNote,
      '/* Site title + article h1 on --font-family-display; h2–h4 use body stack. */',
      '/* code/pre: UA styles use monospace; --font-family-mono sets it explicitly (not the body stack). */',
      '',
      ':root {',
      '  --font-family: ' + bodyFamily + ';',
      '  --font-family-display: ' + headingFamily + ';',
      '  --font-family-mono: ' + monoStack + ';',
      '}',
      '',
      'body {',
      '  font-family: var(--font-family);',
      '}',
      '',
      'hgroup h1, article h1 {',
      '  font-family: var(--font-family-display);',
      '}',
      '',
      'code, pre, kbd, samp {',
      '  font-family: var(--font-family-mono);',
      '}'
    ]
      .filter(function (line) {
        return line.length > 0;
      })
      .join('\n');
  }

  if (bodyFamily === headingFamily) {
    return [
      webNote,
      '/* Tokens + hooks — order is for copying, not matching this site’s CSS file layout. */',
      '/* code/pre: UA styles use monospace; --font-family-mono sets it explicitly (not the body stack). */',
      '',
      ':root {',
      '  --font-family: ' + bodyFamily + ';',
      '  --font-family-mono: ' + monoStack + ';',
      '}',
      '',
      'body {',
      '  font-family: var(--font-family);',
      '}',
      '',
      'code, pre, kbd, samp {',
      '  font-family: var(--font-family-mono);',
      '}'
    ]
      .filter(function (line) {
        return line.length > 0;
      })
      .join('\n');
  }

  return [
    webNote,
    '/* Headings: separate token only when body and heading stacks differ (your choice on a real site). */',
    '/* code/pre: UA styles use monospace; --font-family-mono sets it explicitly (not the body stack). */',
    '',
    ':root {',
    '  --font-family: ' + bodyFamily + ';',
    '  --font-family-headings: ' + headingFamily + ';',
    '  --font-family-mono: ' + monoStack + ';',
    '}',
    '',
    'body {',
    '  font-family: var(--font-family);',
    '}',
    '',
    'h1, h2, h3, h4 {',
    '  font-family: var(--font-family-headings);',
    '}',
    '',
    'code, pre, kbd, samp {',
    '  font-family: var(--font-family-mono);',
    '}'
  ]
    .filter(function (line) {
      return line.length > 0;
    })
    .join('\n');
}

(function () {
  var elJson = document.getElementById('font-stacks-json');
  if (!elJson) return;
  var stacks = JSON.parse(elJson.textContent);
  var byId = {};
  for (var i = 0; i < stacks.length; i++) {
    byId[stacks[i].id] = stacks[i];
  }
  var SAME = 'same-as-headings';
  var selH = document.getElementById('font-heading-stack');
  var selB = document.getElementById('font-body-stack');
  var mixJp = document.getElementById('font-preview-jp');
  var cssOut = document.getElementById('font-css-code');
  function bodyResolved() {
    if (selB.value === SAME) return byId[selH.value];
    return byId[selB.value];
  }
  function applyFonts() {
    var h = byId[selH.value];
    var b = bodyResolved();
    if (!h || !b || !mixJp || !cssOut) return;
    var scope = h.headingScope || 'all-headings';
    mixJp.style.fontFamily = b.family;
    mixJp.querySelectorAll('h1, h2, h3, h4').forEach(function (el) {
      el.style.fontFamily = b.family;
    });
    if (scope === 'hgroup-only') {
      var siteH1 = mixJp.querySelector('header hgroup h1');
      if (siteH1) siteH1.style.fontFamily = h.family;
    } else if (scope === 'h1-titles') {
      mixJp.querySelectorAll('header hgroup h1, article h1').forEach(function (el) {
        el.style.fontFamily = h.family;
      });
    } else {
      mixJp.querySelectorAll('h1, h2, h3, h4').forEach(function (el) {
        el.style.fontFamily = h.family;
      });
    }
    cssOut.textContent = formatFontLabPasteCss(b.family, h.family, {
      headingScope: scope,
      webFont: !!(h.webFont || b.webFont)
    });
  }
  function onHeadingChange() {
    applyFonts();
  }
  function onBodyChange() {
    applyFonts();
  }
  selH.addEventListener('change', onHeadingChange);
  selB.addEventListener('change', onBodyChange);
  applyFonts();
})();

